-- 6001_main_ep01.csv (13 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"肌を焦がすような乾いた風が、荒涼たる砂丘を撫でる音がする。ここは軍事国家たる聖王国ローランの辺境、名もなき村の外れだ。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"かつて栄華を極めた王国の威光もここまで届くことはなく、村の壁は崩れかけ、人々は日々の糧を得るのにも苦労している。","type":"text","bg_key":"bg_road_day","next":"text1_1","choices":[{"label":"続ける","next":"text1_1"}]},"text1_1":{"text":"そんな場所から、君の物語は始まる。名もなき一介の傭兵として身を立てるため、君は王国軍の輸送部隊を手伝う運搬依頼を引き受けた。","type":"text","bg_key":"bg_road_day","next":"text1_2","choices":[{"label":"続ける","next":"text1_2"}]},"text1_2":{"text":"荷馬車に積まれた大量の木箱を数え終えるかどうかの時、背後からしゃがれた太い声が飛んできた。","type":"text","bg_key":"bg_road_day","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"「おい、そこの新入り！ぼんやりするな。太陽が高くなれば、野盗の連中がいつ湧いてきてもおかしくないぞ！」","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"choice1","choices":[{"label":"「急いで積み込みます」","next":"text3"},{"label":"「あんたはここで指図するだけか？」","next":"text3"}]},"text3":{"text":"男は鼻で笑うと、鈍く光る長剣の柄に手を当てた。「威勢はいいが、口ほどにもない奴はすぐ死ぬのが戦場だ」","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text3_1","choices":[{"label":"続ける","next":"text3_1"}]},"text3_1":{"text":"「俺はガウェイン。この部隊の小隊長にして、お前たち新米を死なせないための監視役といったところだ。……お前、その剣の腕には自信があるんだろうな？」","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text4","choices":[{"label":"続ける","next":"text4"}]},"text4":{"text":"君が応えようとしたその瞬間、砂埃の向こうからけたたましい怒声と馬の嘶きが迫ってきた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"text4_1","choices":[{"label":"続ける","next":"text4_1"}]},"text4_1":{"text":"「小隊長！前方の丘より正体不明の集団が接近！十、いや二十……武器を持っています。野盗です！」見張りの兵士の声が裏返る。","type":"text","bg_key":"bg_road_day","next":"text4_2","choices":[{"label":"続ける","next":"text4_2"}]},"text4_2":{"text":"ガウェインが素早く抜刀し、鋭い眼光を砂塵に向ける。「チッ……言葉の先からこれだ。おい新入り、あの木箱は死守しろ。荷を奪われりゃ俺たちの首が飛ぶぞ」","type":"text","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"己の力と生き残る意志を示す、最初の手柄を立てる時が来た。震える手で武器を握り直せ！","type":"battle","bg_key":"bg_road_day","enemy_group_id":"200","enemy_name":"野盗の一隊","enemy_level":3,"choices":[{"label":"迎撃する","next":"text_post_battle"}],"battle_success_next":"text_post_battle"},"text_post_battle":{"text":"剣を振り抜き、最後の一人を砂に沈める。荒い息を吐く君の前で、ガウェインが剣の血振るいをした。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"「悪くない太刀筋だ。これなら戦場でも生き残れるかもしれんな。……さあ、荷馬車を出すぞ！」","type":"end","result":"success","bg_key":"bg_road_day","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","choices":[]}}}'::jsonb, rewards = '{"gold":150,"exp":80,"reputation":5}'::jsonb WHERE id = 6001;

-- 6002_main_ep02.csv (12 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"名もなき村での野盗撃退の功績、あるいは小隊長ガウェインの引き立てにより、君はローランと砂塵王国マルカンドの国境地帯における警備任務に就くこととなった。","type":"text","bg_key":"bg_wasteland","bgm":"bgm_quest_calm","next":"text0_1","choices":[{"label":"続ける","next":"text0_1"}]},"text0_1":{"text":"国境の荒野は見渡す限りの赤茶けた土と、吹き荒れる空風の音ばかりが続く。兵士たちの間には、得体の知れない緊張感が蔓延していた。","type":"text","bg_key":"bg_wasteland","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"「最近、この辺りでは武装した集団が頻繁に出没している。ただのゴロツキや盗賊団にしては、妙に動きに統率が取れているのが気掛かりだ」","type":"text","bg_key":"bg_wasteland","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text1_1","choices":[{"label":"続ける","next":"text1_1"}]},"text1_1":{"text":"ガウェインは厳しい顔で地平線を睨んでいる。「それに……あの野盗どもが使っていた武器の質。どう見てもどこかの正規のものだ」","type":"text","bg_key":"bg_wasteland","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"choice1","choices":[{"label":"「隣国、マルカンドの兵士では？」","next":"text2"},{"label":"「誰であろうと、斬るだけです」","next":"text2"}]},"text2":{"text":"「……かもしれん。マルカンド側も、我が帝国の膨張を警戒して水面下で作戦を展開しているという噂はある。いずれにせよ、油断するなよ」","type":"text","bg_key":"bg_wasteland","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text2_1","choices":[{"label":"続ける","next":"text2_1"}]},"text2_1":{"text":"もしも相手がマルカンドの息のかかった者たちであるならば、これは単なる盗賊討伐ではなく「国境紛争」の引き金になりかねない。君はゴクリと唾を呑み込んだ。","type":"text","bg_key":"bg_wasteland","next":"text3","choices":[{"label":"続ける","next":"text3"}]},"text3":{"text":"やがて、砂丘の向こうから黒い布で顔を覆った集団が、小隊を半包囲するような陣形で音もなく接近してくるのが見えた。","type":"text","bg_key":"bg_wasteland","next":"text3_1","choices":[{"label":"続ける","next":"text3_1"}]},"text3_1":{"text":"その足運びは明らかに素人のそれではない。練度を積んだ軍人の歩法だ。","type":"text","bg_key":"bg_wasteland","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"「舌の根も乾かぬうちに来たぞ！陣形を崩すな、背中を取られるなよ！」","type":"battle","enemy_group_id":"200","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","choices":[{"label":"武器を構える","next":"text_post_battle"}],"battle_success_next":"text_post_battle"},"text_post_battle":{"text":"統率の取れた激しい攻撃を辛くも凌ぎ切り、一帯の制圧に成功した。死体の顔を確認しようと布を剥ぐが、認識章のようなものは一切持っていない。","type":"text","bg_key":"bg_wasteland","next":"text_post_battle2","choices":[{"label":"続ける","next":"text_post_battle2"}]},"text_post_battle2":{"text":"だが、彼らが落とした武器には、意図的に削り潰された「正規軍の紋章」らしき痕跡が残されていた。ガウェインは無言でそれを蹴り飛ばす。","type":"text","bg_key":"bg_wasteland","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"国境地帯に、泥沼の戦乱を予感させる重く不穏な空気が漂い始めている……。","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6002;

-- 6003_main_ep03.csv (15 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"国境地帯での任務を終え、君とガウェインの属する小隊はマルカンド領内にある小さなオアシス都市に駐屯していた。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_mystery","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"ここは本来、両国を繋ぐ貴重な水源地であり、交易の要所として中立的な立場を保っているはずの街だ。","type":"text","bg_key":"bg_desert","next":"text1_1","choices":[{"label":"続ける","next":"text1_1"}]},"text1_1":{"text":"しかし街を歩く人々の瞳には、帝国出身である君たち傭兵や兵士に対する明確な警戒態勢——あるいは憎悪——の色が浮かんでいる。","type":"text","bg_key":"bg_desert","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"ある朝、静寂を切り裂くような悲鳴が広場から上がった。「大変だ！井戸があくせく泡を立てている。何者かが毒を撒いたに違いない！」","type":"text","bg_key":"bg_desert","next":"text2_1","choices":[{"label":"続ける","next":"text2_1"}]},"text2_1":{"text":"街はあっという間に騒然となる。砂漠における水源の喪失は、すなわち街全体の死を意味する。数日でこの街は干上がるだろう。","type":"text","bg_key":"bg_desert","next":"text2_2","choices":[{"label":"続ける","next":"text2_2"}]},"text2_2":{"text":"広場に面した宿屋から飛び出した君は、足元で倒れ伏す町民の姿を目にした。状況は一刻を争う。","type":"text","bg_key":"bg_desert","next":"choice_search","choices":[{"label":"「すぐに周囲を探索する」","next":"search_area"},{"label":"「ガウェインに指示を仰ぐ」","next":"gawain_talk"}]},"gawain_talk":{"text":"「慌てるな。この短時間だ、実行犯はまだ遠くへは行けていないはずだ。慌てて走り回るより、地面の違和感を探せ」","type":"text","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"search_area","choices":[{"label":"続ける","next":"search_area"}]},"search_area":{"text":"砂地と石畳の隙間に残された不自然な足跡。足の運びが深く急いでいるそれは、明らかに町民のものではない。","type":"text","bg_key":"bg_slum","next":"text3","choices":[{"label":"続ける","next":"text3"}]},"text3":{"text":"君はその痕跡を辿り、街の裏手にある岩場へと回った。そこには、毒瓶のようなものを片付けている怪しい影が三人。","type":"text","bg_key":"bg_slum","next":"text3_1","choices":[{"label":"続ける","next":"text3_1"}]},"text3_1":{"text":"「チッ……こんなに早く嗅ぎつけられたか。やはり帝国の猟犬は鼻が利く」","type":"text","bg_key":"bg_slum","next":"text4","choices":[{"label":"続ける","next":"text4"}]},"text4":{"text":"男たちは悪びれる様子もなく、むしろ「帝国への忠誠」を示すような過激な台詞を吐き捨てながら、刃を抜いた。","type":"text","bg_key":"bg_slum","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"彼らは帝国軍の強硬派を名乗る工作員たちだった。この街に戦争の火種を落とし、大義名分を作ろうとしているのだ！","type":"battle","enemy_group_id":"201","choices":[{"label":"「なぜこんな非道を！」","next":"text_post_battle"}],"battle_success_next":"text_post_battle"},"text_post_battle":{"text":"工作員たちを撃退し、懐から解毒薬らしき成分を確保することに成功した。死の間際、口から血を流す男が薄ら笑いを浮かべる。","type":"text","bg_key":"bg_slum","next":"text_post_battle2","choices":[{"label":"続ける","next":"text_post_battle2"}]},"text_post_battle2":{"text":"「遅いさ……。火種はもはや止められん。俺たちの血が、聖戦の狼煙となるのだ……」","type":"text","bg_key":"bg_slum","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"解毒薬により井戸の最悪の事態は免れたが、これが仕組まれた「開戦の口実」であることは明白だった。君の胸に、重い鉛のような感情が沈んでいく。","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6003;

-- 6004_main_ep04.csv (13 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"オアシス都市での一件から数日後。君とガウェインは、マルカンド領内を移動する大規模な中立商隊の護衛任務に就いていた。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"毒物事件の噂は瞬く間に広がり、マルカンド側の帝国に対するヘイトは限界に達している。すれ違う商人たちの目つきも鋭い。","type":"text","bg_key":"bg_desert","next":"text1_1","choices":[{"label":"続ける","next":"text1_1"}]},"text1_1":{"text":"「いつ火を吹いてもおかしくない。……むしろ、上層部は火が吹くのを待っているようにも見えるな」","type":"text","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"ガウェインが馬上でそう呟き、深く溜息をついた直後だった。","type":"text","bg_key":"bg_desert","next":"text2_1","choices":[{"label":"続ける","next":"text2_1"}]},"text2_1":{"text":"凄まじい轟音と共に、隊商の先頭付近で巨大な爆発・砂塵が上がり、護衛の兵士や商人たちが吹き飛ばされた！","type":"text","bg_key":"bg_desert","next":"text3","choices":[{"label":"続ける","next":"text3"}]},"text3":{"text":"「敵襲！！……馬鹿な、あれを見ろ！信じられん、ローランの紋章だと！？」","type":"text","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text3_1","choices":[{"label":"続ける","next":"text3_1"}]},"text3_1":{"text":"砂煙の中から姿を現したのは、他ならぬ君たちの祖国――聖帝国ローランの正規軍、その先遣隊だった。","type":"text","bg_key":"bg_desert","next":"text4","choices":[{"label":"続ける","next":"text4"}]},"text4":{"text":"宣戦布告などない。彼らは『大義』や『制裁』といった空虚な言葉を並べ立てながら、丸腰同然のマルカンド商隊に容赦なく牙を剥いた。","type":"text","bg_key":"bg_desert","next":"text4_1","choices":[{"label":"続ける","next":"text4_1"}]},"text4_1":{"text":"「これが……大義を掲げた国のやることか！俺たちは何のために剣を振るっているんだ！」君は思わず叫んだ。","type":"text","bg_key":"bg_desert","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"迷っている暇はない。今は目の前で殺されようとしている人々を救うため、同国人に向かって剣を抜くしかなかった。","type":"battle","enemy_group_id":"202","choices":[{"label":"「商隊を護る！」","next":"text_post_battle"}],"battle_success_next":"text_post_battle"},"text_post_battle":{"text":"帝国兵を退け、先遣隊を一時的に後退させることには成功した。しかし、辺り一面には無残な商隊の残骸と遺体が散乱している。","type":"text","bg_key":"bg_desert","next":"text_post_battle2","choices":[{"label":"続ける","next":"text_post_battle2"}]},"text_post_battle2":{"text":"「……ついに、開戦の口火が切られてしまったか。引き返せない泥沼の始まりだ」","type":"text","bg_key":"bg_desert","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"ガウェインの顔に深く刻まれた疲労と絶望は、これから始まる地獄の戦場を予見していた。君の手は、同朋を斬った感触に小刻みに震えている。","type":"end","result":"success","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","choices":[]}}}'::jsonb WHERE id = 6004;

-- 6005_main_ep05.csv (14 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"開戦の口火が切られてから数週間。君たちは、なし崩し的にマルカンド王国の前線拠点での防衛戦に巻き込まれていた。","type":"text","bg_key":"bg_bandit_camp","bgm":"bgm_quest_crisis","next":"text0_1","choices":[{"label":"続ける","next":"text0_1"}]},"text0_1":{"text":"傭兵として雇い主（マルカンド側）に付くか、祖国（ローラン）の軍に下るか。戦場の混乱の中で、そんな選択肢など意味を持たなかった。生き残るために目の前の敵を斬る、それだけだ。","type":"text","bg_key":"bg_bandit_camp","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"突如として大地の揺れる音が響く。地平線を埋め尽くすほどの砂埃を上げて、帝国軍の本隊が拠点への全面侵攻を開始したのだ。","type":"text","bg_key":"bg_bandit_camp","next":"text1_1","choices":[{"label":"続ける","next":"text1_1"}]},"text1_1":{"text":"「もはや小競り合いではない……本物の戦争だ！各員、死にたくなければ配置につけ！」ガウェインの悲痛ともとれる叫びが戦場に響き渡る。","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"text":"怒涛の如く押し寄せる帝国兵の群れ。彼らの目には熱狂的な『大義』が宿っており、命の惜しさなど微塵も感じられない。まずは先陣を切り抜けろ！","type":"battle","enemy_group_id":"203","choices":[{"label":"狂気の群れに剣を振るう","next":"text2"}],"battle_success_next":"text2"},"text2":{"text":"数名を切り伏せたが、敵の数は減るどころか津波のように増していく。仲間の傭兵やマルカンドの兵士たちが次々と赤い海に沈んでいく。","type":"text","bg_key":"bg_bandit_camp","next":"text2_1","choices":[{"label":"続ける","next":"text2_1"}]},"text2_1":{"text":"矢衾の中から、重装装甲に身を包んだ帝国の精鋭部隊が現れた。彼らの標的は、最前線で踏み留まっているガウェインだ。","type":"text","bg_key":"bg_bandit_camp","next":"text3","choices":[{"label":"続ける","next":"text3"}]},"text3":{"text":"「無理だ、多すぎる！……新入り、お前はまだ死ぬべきではない。ここはワシが引き受ける、お前だけでも逃げろ！」","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"text3_1","choices":[{"label":"続ける","next":"text3_1"}]},"text3_1":{"text":"「そんなことできるわけが――」君の言葉を、耳を劈く烈白な剣戟の音が遮った。","type":"text","bg_key":"bg_bandit_camp","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"text":"ガウェインが君の前に立ち塞がり、精鋭たちの猛攻をその巨大な盾と剣で受け止める。その背後から迫る別働隊の刃が、君に向かって牙を剥いた！","type":"battle","enemy_group_id":"203","choices":[{"label":"死力を尽くし、生き延びる","next":"text4"}],"battle_success_next":"text4"},"text4":{"text":"死に物狂いで別働隊を退けた。だが、息をつく暇もなく振り返った君の目に飛び込んできたのは――無数の槍や剣に貫かれ、血だまりの中に崩れ落ちる老騎士の姿だった。","type":"text","bg_key":"bg_bandit_camp","next":"text4_1","choices":[{"label":"続ける","next":"text4_1"}]},"text4_1":{"text":"「ガウェイン……ッ！！」君は泥に塗れた手を伸ばすが、届かない。彼を貫いた兵士たちは、すでに次の獲物を探して遠ざかっていた。","type":"text","bg_key":"bg_bandit_camp","next":"text5","choices":[{"label":"続ける","next":"text5"}]},"text5":{"text":"「……行け。……新米。生き延びて、この目で……世界の果てを、見届けろ……」","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_gawain.png","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"それが、厳しいながらも君を導き続けた老騎士の最期の言葉だった。大義という名の下に散った数多の命の重さを背負い、敗走兵となった君の孤独な真の旅がはじまる。","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6005;

-- 6006_main_ep06.csv (12 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"泥と血に塗れた敗残兵の群れに紛れ、マルカンドの前線拠点から逃げ延びた君は、東の果て——夜刀神国の国境域である密林地帯へと足を踏み入れていた。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_calm","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"肩の傷が熱を持つ。目を閉じれば、今でも無数の槍に貫かれて笑った老騎士、ガウェインの最期の顔がフラッシュバックする。","type":"text","bg_key":"bg_forest_day","next":"text1_1","choices":[{"label":"続ける","next":"text1_1"}]},"text1_1":{"text":"「生き延びて、この目で世界の果てを見届けろ……」その呪いのような、祈りのような言葉だけが、今の君を突き動かしていた。","type":"text","bg_key":"bg_forest_day","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"しかし現実は過酷だ。帝国の執拗な残党狩りの捜索網が敷き詰められ、水筒はとうに空。食料も底を突いている。","type":"text","bg_key":"bg_forest_day","next":"text2_1","choices":[{"label":"続ける","next":"text2_1"}]},"text2_1":{"text":"遠くから、軍用犬の吠え声と軍靴の足音が聞こえてくる。休息を取る時間は残されていない。だが、どちらへ逃げるべきか。","type":"text","bg_key":"bg_forest_day","next":"choice1","choices":[{"label":"「険しい『けもの道』を進む」","next":"text_safepath"},{"label":"「見つかりやすいが『川沿い』を急ぐ」","next":"text_danger"}]},"text_safepath":{"text":"足場は最悪で、蔦や棘が容赦なく体力を奪っていく。（Vitality-5）","type":"text","bg_key":"bg_forest_day","next":"text_safepath_2","choices":[{"label":"続ける","next":"text_safepath_2"}]},"text_safepath_2":{"text":"だがその甲斐あって、追手の目を完全に欺くことに成功した。疲労困憊になりながらも密林を抜ける。","type":"text","bg_key":"bg_forest_day","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"text_danger":{"text":"川のせせらぎが喉の渇きを癒してくれる。だが、開けた場所に出た代償はすぐに支払わされることとなった。","type":"text","bg_key":"bg_river","next":"text_danger_2","choices":[{"label":"続ける","next":"text_danger_2"}]},"text_danger_2":{"text":"茂みが揺れ、帝国軍の追討部隊が姿を現す。「見つけたぞ！マルカンドの残党だ。一人残らず首を刎ねろ！」","type":"text","bg_key":"bg_river","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"生き延びると決めたんだ。こんなところで犬死にするわけにはいかない！","type":"battle","enemy_group_id":"204","choices":[{"label":"血路を切り開く","next":"text_danger_3"}],"battle_success_next":"text_danger_3"},"text_danger_3":{"text":"追討部隊を返り討ちにすると、君は血のついた剣を洗いもせずに走り出した。","type":"text","bg_key":"bg_river","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"幾多の苦難を越え、密林が途切れる。その先には、重厚な木造建築が並ぶ夜刀神国の『関所』が、巨大な影を落として君を待っていた。","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6006;

-- 6007_main_ep07.csv (12 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"鬱蒼と生い茂る密林地帯を抜け、君は東の果てに位置する島国、夜刀神国の国境関所へと辿り着いた。","type":"text","bg_key":"bg_spot_yato_entrance","bgm":"bgm_quest_mystery","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"巨大な木組みの門が威圧的に聳え立ち、屈強な関守たちが物々しい警戒を敷いている。最近の近隣諸国の戦乱を受けて、入国審査は異常なほど厳格化されていた。","type":"text","bg_key":"bg_spot_yato_entrance","next":"text1_1","choices":[{"label":"続ける","next":"text1_1"}]},"text1_1":{"text":"君の手の中には、マルカンドから逃れる道中で息絶えた名もなきローラン兵から託された「帝国の機密書」が握られている。これを然るべき者へ届けるのが、今の君の数少ない目的だった。","type":"text","bg_key":"bg_spot_yato_entrance","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"「止まれ。何者だ」刀に手をかけた関守の頭目が、冷酷な目で君を見下ろしている。「通行証を持たぬ流れ者は通せぬ。怪しい真似をするならここで斬る。さっさと立ち去れ」","type":"text","bg_key":"bg_spot_yato_entrance","next":"choice1","choices":[{"label":"「『機密書』を売るので通してくれ（裏切り）」","next":"path_betray"},{"label":"「傭兵として雇ってくれ（正攻法）」","next":"path_normal"}]},"path_betray":{"text":"「……ほう？」関守の顔色が変わる。機密書を受け取った彼は、中身を軽く検めるとニヤリと笑った。「なるほど、裏切りの代償というわけか。……良かろう、通れ」","type":"text","bg_key":"bg_spot_yato_entrance","next":"text2_betray","choices":[{"label":"続ける","next":"text2_betray"}]},"text2_betray":{"text":"関所の門が開く。だが、本来届けるべき目的地を裏切り、死者の想いを金と安全に換えたその事実は、君の心に冷たい影を落とした。（※名声が低下した）","type":"text","bg_key":"bg_spot_yato_entrance","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"path_normal":{"text":"君の提案に関守は鼻で笑った。「腕組みの傭兵だと？お前のようなボロボロの敗残兵にか？……ならば実力を示せ。ちょうど裏山に巣食う大蛇の駆除に手を焼いていたところだ」","type":"text","bg_key":"bg_spot_yato_entrance","next":"path_normal_2","choices":[{"label":"続ける","next":"path_normal_2"}]},"path_normal_2":{"text":"「あれの首を刎ねてくれば、特例で通行を許可してやろう」関守の言葉は半分以上が冷やかしだったが、君に別の選択肢はなかった。","type":"text","bg_key":"bg_spot_yato_entrance","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"薄暗い裏山の竹林。血と獣の臭いが立ち込める中、人間を丸呑みにするほどの巨大な蛇の群れが、君を獲物と見定めて這い寄ってきた！","type":"battle","enemy_group_id":"205","choices":[{"label":"剣を抜き、死闘に身を投じる","next":"text2_normal"}],"battle_success_next":"text2_normal"},"text2_normal":{"text":"血まみれの大蛇の首を関所の中庭へ投げ捨てると、周囲の兵士たちがどよめき、関守の頭目は絶句した。","type":"text","bg_key":"bg_spot_yato_entrance","next":"text2_normal_2","choices":[{"label":"続ける","next":"text2_normal_2"}]},"text2_normal_2":{"text":"「……見事な腕だ。まさか本当に討ち取るとはな。……通れ、名もなき傭兵よ。夜刀神国はお前のような強者を歓迎する」","type":"text","bg_key":"bg_spot_yato_entrance","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"重い音を立てて関所の門が開く。異国の風が吹き抜ける中、夜刀特有の瓦屋根の風景が、君の目の前に広がった。","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6007;

-- 6008_main_ep08.csv (11 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"夜刀神国に入境して数日が経った。君は都からは遠く離れた、辺境に近い寂れた宿屋で久しぶりの休息を取っていた。","type":"text","bg_key":"bg_tavern_night","bgm":"bgm_quest_tense","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"粗末なベッドに横たわり、これまでの激戦で負った傷を癒す。だが、傭兵として染み付いた勘が、無意識に危険を察知して君の眠りを浅くしていた。","type":"text","bg_key":"bg_tavern_night","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"真夜中。窓の外で、草木が擦れるのとは明らかに違う、衣擦れの音が微かに響いた。さらには窓ガラスが立てる、細かく不自然な振動。","type":"text","bg_key":"bg_tavern_night","next":"text3","choices":[{"label":"続ける","next":"text3"}]},"text3":{"text":"「……囲まれているな。しかもプロだ」君はゆっくりと身を起こし、枕元に置いていた剣の柄を握る。","type":"text","bg_key":"bg_tavern_night","next":"text3_1","choices":[{"label":"続ける","next":"text3_1"}]},"text3_1":{"text":"この国は平穏に見えて、裏では各勢力が血みどろの暗闘を繰り広げている。君が関所に現れた情報、あるいは帝国の生き残りであるという事実が、誰かの気に障ったのだろうか。","type":"text","bg_key":"bg_tavern_night","next":"text4","choices":[{"label":"続ける","next":"text4"}]},"text4":{"text":"次の瞬間、扉が音もなく吹き飛び、煙幕と共に黒装束の集団が部屋になだれ込んできた！","type":"text","bg_key":"bg_tavern_night","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"「標的を確認。……これより排除する」感情の一切こもっていない声と共に、鋭い刃が暗闇から迫る。","type":"battle","enemy_group_id":"206","choices":[{"label":"暗闇の中で迎撃する","next":"text5"}],"battle_success_next":"text5"},"text5":{"text":"数合の打ち合いの末、第一波を切り伏せた。だが、死体は音もなく崩れ落ち、悲鳴一つ上げない。","type":"text","bg_key":"bg_tavern_night","next":"text5_1","choices":[{"label":"続ける","next":"text5_1"}]},"text5_1":{"text":"「ただのゴロツキじゃない……夜刀の暗部（プロ）か！」息をつく暇もなく、窓からさらなる刺客が音もなく滑り込んでくる。","type":"text","bg_key":"bg_tavern_night","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"text":"「抵抗は無意味だ。貴様はここで夜霧に消える運命にある」月明かりに照らされた刃が乱舞する！","type":"battle","enemy_group_id":"207","choices":[{"label":"生き残るために命を削る","next":"end_node"}],"battle_success_next":"end_node"},"end_node":{"text":"最後の刺客を窓の外へ蹴り落とすと、夜は再び不気味なほどの静寂を取り戻した。誰が、何の目的で刺客を差し向けたのか……夜刀の闇は深く、底知れないほど冷たい。","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6008;

-- 6009_main_ep09.csv (11 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"暗殺者による襲撃を凌ぎ、腕の立つ傭兵としての名が少しずつ夜刀の裏社会で囁かれ始めた頃。君の元に、有力な大名からの直接指名で護衛依頼が舞い込んだ。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"依頼内容は、領地内を横断する大名行列の護衛。表向きは「近隣の古社へ向けた祭礼行事の移動」だと説明されているが、その物々しい装備の量には明らかに違和感があった。","type":"text","bg_key":"bg_mountain","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"「皆の者、決して油断するな。いつ何時、野盗や『逆賊』が襲い掛かるとも知れんぞ！」護衛団長が神経質そうに声を荒げる。","type":"text","bg_key":"bg_mountain","next":"text2_1","choices":[{"label":"続ける","next":"text2_1"}]},"text2_1":{"text":"行軍が険しい山道に差し掛かった時だった。両側の崖上から大量の岩が落とされ、行列の足が強制的に止められる。","type":"text","bg_key":"bg_mountain","next":"text3","choices":[{"label":"続ける","next":"text3"}]},"text3":{"text":"土埃の向こうから、ボロボロの着物を纏い、農具や竹槍で武装した集団が雪崩のように押し寄せてきた。彼らの顔にあるのは野盗の卑しさではなく、餓えた獣のような必死さだ。","type":"text","bg_key":"bg_mountain","next":"text3_1","choices":[{"label":"続ける","next":"text3_1"}]},"text3_1":{"text":"「米を返せ！！その荷台に乗せられているのは、我らの村から不当に収奪した年貢の米だ！家族が餓死しそうなのに、何が祭礼だ！」襲撃者の一人が血を吐くように叫ぶ。","type":"text","bg_key":"bg_mountain","next":"text4","choices":[{"label":"続ける","next":"text4"}]},"text4":{"text":"「黙れ逆賊ども！その汚い手で殿の荷に触れるな！者ども、討ち捨てい！」護衛団長は顔を真っ赤にして苛烈な命令を下す。","type":"text","bg_key":"bg_mountain","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"彼らは逆賊か、それとも強欲な権力者の被害者か。だが、君は金を受け取って『現在』の雇用主を守る傭兵だ。君の剣は、誰の正義のためにあるのか？","type":"battle","enemy_group_id":"208","choices":[{"label":"刃で応える","next":"text_post_battle"}],"battle_success_next":"text_post_battle"},"text_post_battle":{"text":"君の剣が閃くたびに、悲痛な叫び声を上げて農民たちが倒れていく。訓練された兵士たちによって、一揆は瞬く間に鎮圧された。","type":"text","bg_key":"bg_mountain","next":"text_post_battle2","choices":[{"label":"続ける","next":"text_post_battle2"}]},"text_post_battle2":{"text":"「ふん、虫ケラどもが。……おい傭兵、よくやった。後で特別手当を払ってやろう」団長は満足げに笑った。","type":"text","bg_key":"bg_mountain","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"倒れた襲撃者たちの手には、折れたクワや鎌がこびりついていた。血に染まった彼らの貧相な装備を見つめながら、君はただ静かに、冷たくなった剣を鞘に納めた。","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6009;

-- 6010_main_ep10.csv (11 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"夜刀神国の深奥部、誰も立ち入らないとされる禁域の古代神殿。君は一連の騒乱――大名行列の襲撃や暗部たちの不気味な暗躍――を裏で操っていた「黒幕」の痕跡を追って、ここまでやってきた。","type":"text","bg_key":"bg_boss_altar","bgm":"bgm_quest_crisis","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"神殿の内部は異様な空気に満ちていた。苔むした石畳の奥に、人の手によるものではない、神々しい光を放つ巨大な「神託の祭壇」が鎮座している。","type":"text","bg_key":"bg_boss_altar","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"祭壇の周囲には、これまで君が越えてきた国々の幻影――炎上するマルカンドの砂漠、血に染まるローランの城壁、そして夜刀の竹林――が、水晶玉のように浮かび上がっていた。","type":"text","bg_key":"bg_boss_altar","next":"text3","choices":[{"label":"続ける","next":"text3"}]},"text3":{"text":"『……地上の穢れ、規定量に達す。闘争の気、収穫を完了。これより第3フェーズ・地上の大浄化へ移行する』","type":"text","bg_key":"bg_boss_altar","next":"text3_1","choices":[{"label":"続ける","next":"text3_1"}]},"text3_1":{"text":"感情を一切持たない非情な「使徒」の声が、頭の中に直接響き渡る。君はその声の色に、背筋が凍るような絶望を覚えた。","type":"text","bg_key":"bg_boss_altar","next":"text4","choices":[{"label":"続ける","next":"text4"}]},"text4":{"text":"ローランの大義も、マルカンドの防衛も、夜刀神国の一揆も。全ては人間同士の意思ではなく、この「天上の神々」によって仕組まれ、コントロールされた「間引き」の遊戯に過ぎなかったのだ。","type":"text","bg_key":"bg_boss_altar","next":"text4_1","choices":[{"label":"続ける","next":"text4_1"}]},"text4_1":{"text":"「ふざけるな……。俺たちが、あの老騎士が流した血は……盤上の駒の戯れだったと言うのか！」君は剣を抜き放ち、祭壇に向かって怒声を上げた。","type":"text","bg_key":"bg_boss_altar","next":"text5","choices":[{"label":"続ける","next":"text5"}]},"text5":{"text":"『不浄なる因子の接近を感知。神の理に刃向かう愚者よ。……神代の守護竜、顕現せよ』","type":"text","bg_key":"bg_boss_altar","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"祭壇の光が激しく明滅し、空間が裂ける。そこから現れたのは、現代の魔獣とは次元が違う、圧倒的な質量と魔力を持った純白の巨竜だった。","type":"battle","enemy_group_id":"209","choices":[{"label":"神の理に叛逆する","next":"text_post_battle"}],"battle_success_next":"text_post_battle"},"text_post_battle":{"text":"幾度も死の淵を彷徨いながらも、君の剣がついに守護竜の逆鱗を貫いた。光の粒子となって消え去る巨竜の残骸を見下ろし、荒い息を吐く。","type":"text","bg_key":"bg_boss_altar","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"しかし、真の絶望はこれからだ。祭壇の水晶には「天上の神々」の傲慢な瞳が、未だ世界中を見下ろしている光景が映し出されていた。神々の遊戯は終わっていない。（第2部完）","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6010;

-- 6011_main_ep11.csv (12 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"夜刀の古代神殿で知った世界の真実――天上の神々による理不尽な生態系間引き（大粛清）を阻止するべく、君は東方の超大国「華龍神朝」へと足を踏み入れた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"華龍の広大な大地は、豊かな穀倉地帯と雄大な黄河が流れ、独自の活気に満ちている。だが、辺境の村に身を休めていたある日、突如として空が異様な黄金色に染まり始めた。","type":"text","bg_key":"bg_road_day","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"「なんだあの空は……？太陽が……三つあるのか！？」村人たちが空を指差し、怯えた声を上げる。","type":"text","bg_key":"bg_road_day","next":"text2_1","choices":[{"label":"続ける","next":"text2_1"}]},"text2_1":{"text":"空を覆う黄金の雲の中から、天を貫くような無機質で圧倒的な声が響き渡った。","type":"text","bg_key":"bg_road_day","next":"text3","choices":[{"label":"続ける","next":"text3"}]},"text3":{"text":"『地上の穢れを焼却せよ。これより、神罰の執行を開始する』","type":"text","bg_key":"bg_ruins_field","next":"text3_1","choices":[{"label":"続ける","next":"text3_1"}]},"text3_1":{"text":"声と共に、雲を割って無数の光の輪が降り注ぐ。その輪の中から現れたのは、白磁の装甲と純白の翼を持つ異形の戦士——「上位使徒（天使）」の群れだった。","type":"text","bg_key":"bg_ruins_field","next":"text4","choices":[{"label":"続ける","next":"text4"}]},"text4":{"text":"彼らは言葉を発することなく、手にした光の槍で容赦なく逃げ惑う村人たちを貫いていく。人間と神兵とでは、文字通り次元が違った。","type":"text","bg_key":"bg_ruins_field","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"「ふざけるな……こんな一方的な虐殺が許されてたまるか！」君は震える足を叩き、絶望的な戦力差の天敵へと刃を向けた。","type":"battle","enemy_group_id":"210","choices":[{"label":"戦列に加わる","next":"text5"}],"battle_success_next":"text5"},"text5":{"text":"神使の一体を退けたものの、君の剣は酷く刃こぼれを起こしていた。そして空を見上げれば、倒した数の十倍以上の使徒が新たに降下してきている。","type":"text","bg_key":"bg_ruins_field","next":"text5_1","choices":[{"label":"続ける","next":"text5_1"}]},"text5_1":{"text":"（勝てない……俺一人の力では、どう足掻いても届かない！）","type":"text","bg_key":"bg_ruins_field","next":"text6","choices":[{"label":"続ける","next":"text6"}]},"text6":{"text":"一介の傭兵である君の前に、文字通り「神の壁」という絶対的な絶望が立ち塞がろうとしていた。","type":"text","bg_key":"bg_ruins_field","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"一時撤退を余儀なくされ、君は燃え盛る村を背に華龍の中心部へと走った。このままでは世界中が、神の光という名の炎に飲み込まれることになる。","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6011;

-- 6012_main_ep12.csv (12 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"華龍神朝の命綱であり、国を東西に分断する大河「黄河」。君は神朝の正規軍に合流し、そこで決死の防衛線を張っていた。","type":"text","bg_key":"bg_river","bgm":"bgm_quest_crisis","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"河川敷には数万規模の華龍軍が展開しているが、彼らの顔にあるのは武者震いではなく、天上の脅威に対する根源的な恐怖だった。","type":"text","bg_key":"bg_river","next":"text1_1","choices":[{"label":"続ける","next":"text1_1"}]},"text1_1":{"text":"「来たぞ……川面を見ろ！」誰かが叫ぶ。川上から、まるで流氷のように白い大群が押し寄せてくる。白磁の鎧を纏った使徒の群れだ。","type":"text","bg_key":"bg_river","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"「防衛陣形を崩すな！弓兵、放て！」神朝の老将軍の号令と共に、果てしない神との連戦の幕が上がる。","type":"text","bg_key":"bg_river","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"text":"第一波。空と川面の両方から、天界の尖兵たちが一斉に光の魔法を放ちながら迫る！","type":"battle","enemy_group_id":"211","choices":[{"label":"迎撃する","next":"text3"}],"battle_success_next":"text3"},"text3":{"text":"君を含めた前線部隊の必死の奮闘で第一波を押し返したが、使徒たちは死体を残さない。光となって消え、また新たな群れが補充されるだけだ。","type":"text","bg_key":"bg_river","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"text":"間髪入れずに第二波が到達する。敵の放つ魔力の激しさが一段と増し、防衛線の一部が崩壊を始めた！","type":"battle","enemy_group_id":"211","choices":[{"label":"死線を越える","next":"text4"}],"battle_success_next":"text4"},"text4":{"text":"体力の限界に達し、腕が引き千切れそうなほどの疲労の中で、天が割れた。雲の間から、一際巨大な六枚の翼を持つ熾天使（上位使徒）が降臨する。","type":"text","bg_key":"bg_river","next":"text4_1","choices":[{"label":"続ける","next":"text4_1"}]},"text4_1":{"text":"その圧倒的な威圧感に、華龍の兵士たちが次々と膝をつき、戦意を喪失していく。だが、君だけは剣を杖代わりに立ち上がった。","type":"text","bg_key":"bg_river","next":"battle3","choices":[{"label":"続ける","next":"battle3"}]},"battle3":{"text":"第三波・熾天使（上位使徒）。こいつさえ倒せば、この前線はいったん持ちこたえられるはずだ！","type":"battle","enemy_group_id":"212","choices":[{"label":"すべてを賭して戦う","next":"text_post_battle"}],"battle_success_next":"text_post_battle"},"text_post_battle":{"text":"君の放った一撃が熾天使の胸を貫き、耳を聾するほどの轟音と共に光の粒となって消散した。それを合図にしたかのように、周囲の神兵たちも黄河を退き、天へ帰せられていった。","type":"text","bg_key":"bg_river","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"なんとか防衛線を死守したものの、被害は甚大だった。華龍軍の半数が壊滅し、川底には沈んだ人間の死体が無数に転がっている。「これが……神の力か」君はその場に崩れ落ちた。","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6012;

-- 6013_main_ep13.csv (10 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"黄河の大防衛戦を生き延びた君は、負傷兵たちでごった返す後方の野戦陣地で、ある一人の男と出会った。","type":"text","bg_key":"bg_bandit_camp","bgm":"bgm_quest_tense","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"無精髭を生やし、酒瓶を傾ける老境の剣士。だが、その瞳の奥には異常なほど獰猛な狂気と、計り知れない覇気が宿っている。","type":"text","bg_key":"bg_bandit_camp","next":"text1_1","choices":[{"label":"続ける","next":"text1_1"}]},"text1_1":{"text":"彼は噂に名高い「不死の傭兵王」――ヴォルグ。これまで数え切れないほどの戦場を渡り歩き、死線を超え続けてきた生きた伝説だった。","type":"text","bg_key":"bg_bandit_camp","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"「……よくここまで生き延びたな、若僧。だが、お前の眼はもう限界だと叫んでいるぜ」ヴォルグは君の剣を見て、鼻で笑った。","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_volg.png","next":"text3","choices":[{"label":"続ける","next":"text3"}]},"text3":{"text":"「神だか何だか知らねェが、相手が強すぎるって顔だ。だがな、壁を越えられねぇ奴はここで死ぬ。生き恥を晒して老いさらばえるか、世界を変える特異点になるか……俺に証明してみせろ！」","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_volg.png","next":"text4","choices":[{"label":"続ける","next":"text4"}]},"text4":{"text":"ヴォルグが背に負った大剣を抜いた瞬間、周囲の空気が重く沈み込んだ。先ほど黄河で対峙した熾天使すら凌駕するほどの、濃密な血の匂いと殺気が君を包み込む。","type":"text","bg_key":"bg_bandit_camp","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"彼との戦いは、神を討つための試練だ。伝説の傭兵王を越えられなくて、どうして天上の神々を討てようか！","type":"battle","enemy_group_id":"213","choices":[{"label":"限界を越えて証明する","next":"text_post_battle"}],"battle_success_next":"text_post_battle"},"text_post_battle":{"text":"火花の散る激しい打ち合い。君の体力はとっくに尽きていたが、死地で研ぎ澄まされた直感が、最後の一撃を誘導した。重い剣撃を紙一重で躱し、君の切っ先がヴォルグの首筋で止まる。","type":"text","bg_key":"bg_bandit_camp","next":"text_post_battle2","choices":[{"label":"続ける","next":"text_post_battle2"}]},"text_post_battle2":{"text":"「……フン、悪くない。ギリギリで命を拾ったな」ヴォルグは満足げに笑い、大剣を下ろした。","type":"text","bg_key":"bg_bandit_camp","speaker_image_url":"/images/npcs/npc_guest_volg.png","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"「お前なら、あの『天上の神』の眉間に一矢報いれるかもしれんな。……行け。俺たちの代わりに、神の玉座に唾を吐いてこい！」その言葉を受けた君の目に、再び強い光が宿った。","type":"end","result":"success","speaker_image_url":"/images/npcs/npc_guest_volg.png","choices":[]}}}'::jsonb WHERE id = 6013;

-- 6014_main_ep14.csv (9 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"不死の傭兵王ヴォルグから「神殺しの覚悟」を受け取った直後だった。華龍神朝の首都周辺に、天界から何十本もの聖なる光の柱が狂ったように降り注ぎ始めた。","type":"text","bg_key":"bg_slum","bgm":"bgm_quest_crisis","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"空が文字通り割れ、その裂け目から神々が遣わした「破滅の巨竜（巨兵）」が次々と降下してくる。それはもはや戦争ではなく、一方的な蹂躙――神の怒りの具現化だった。","type":"text","bg_key":"bg_slum","next":"text1_1","choices":[{"label":"続ける","next":"text1_1"}]},"text1_1":{"text":"「逃げろ！とにかく西へ走れェ！」繁栄を誇った東洋の大都市が、一瞬にして瓦礫と神の炎に包まれていく。大通りは阿鼻叫喚の地獄絵図と化していた。","type":"text","bg_key":"bg_slum","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"「民間人を逃がせ！我々が殿（しんがり）を務める！」残存する傭兵や華龍の兵士たちが、決死の覚悟で巨竜たちの前に立ち塞がる。","type":"text","bg_key":"bg_slum","next":"text2_1","choices":[{"label":"続ける","next":"text2_1"}]},"text2_1":{"text":"彼らもまた、死の恐怖に震えている。だが、背後で泣き叫ぶ子供たちの声を背に受けてなお、一歩も退こうとはしなかった。","type":"text","bg_key":"bg_slum","next":"text3","choices":[{"label":"続ける","next":"text3"}]},"text3":{"text":"君もまた、その中の一人として最前線に立った。「……俺も、少しはガウェインのような顔立ちになってきたか」君は自嘲気味に笑い、剣を強く握り直す。","type":"text","bg_key":"bg_slum","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"逃げ遅れた民の背中を守るため、君は迫り来る数機もの神の巨竜の前に立ちはだかった。これは勝つための戦いではない。時間を稼ぐための、「死の舞」だ。","type":"battle","enemy_group_id":"214","choices":[{"label":"一歩も退かずに迎え撃つ","next":"text_post_battle"}],"battle_success_next":"text_post_battle"},"text_post_battle":{"text":"全身が血に塗れ、骨が軋む。何体の巨竜を地に伏せさせたかも覚えていない。だが、君の後ろにはもう、逃げ惑う民の姿はなかった。避難は完了したのだ。","type":"text","bg_key":"bg_slum","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"華龍の絢爛たる首都は完全に失われたが、多くの命を救い出すことには成功した。残るは、この理不尽な破壊を強いる元凶――天界への門を開き、元凶を断ち切ることだけだ。","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6014;

-- 6015_main_ep15.csv (11 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"完全に崩壊し、焦土と化した都市の先に、空間の歪み――次元の裂け目のような異界への扉が口を開けていた。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_crisis","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"それは「天界への門」と呼ばれる、神々の領域へと続く結界だった。門の奥からは、地上の穢れを全て焼き尽くそうとする強烈な魔力が漏れ出ている。","type":"text","bg_key":"bg_ruins_field","next":"text1_1","choices":[{"label":"続ける","next":"text1_1"}]},"text1_1":{"text":"君は体を引き摺りながら、たった一人でその門の前に立った。君の背中には、これまで関わってきた数え切れないほどの命と、散っていった者たちの想いが乗っている。","type":"text","bg_key":"bg_ruins_field","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"『最終防衛ライン突破ヲ確認。これヨリ本機ハ最上位形態へと移行シ、地上ノ完全大粛清ヲ執行スル』","type":"text","bg_key":"bg_spot_karyu_thunder","next":"text2_1","choices":[{"label":"続ける","next":"text2_1"}]},"text2_1":{"text":"裂け目から姿を現したのは、神の意志を直接代行する最強の使徒（ボス）だった。これまでの魔族や使徒たちとは次元の違うプレッシャーが、空間全体を押し潰さんばかりに膨れ上がる。","type":"text","bg_key":"bg_spot_karyu_thunder","next":"text3","choices":[{"label":"続ける","next":"text3"}]},"text3":{"text":"（――ここまでか）君は一瞬だけ、己の限界を悟った。どんなに抗っても、人間一人の生涯では、天上の神々という絶対的な理には届かないのかもしれない。","type":"text","bg_key":"bg_spot_karyu_thunder","next":"text3_1","choices":[{"label":"続ける","next":"text3_1"}]},"text3_1":{"text":"だが、退くわけにはいかない。君がここで戦う姿は、必ず誰かの……『次なる時代』の誰かの道標となるはずだ！","type":"text","bg_key":"bg_spot_karyu_thunder","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"「来い、神の遣い！俺の命と引き換えに、てめえのその冷たい羽を毟り取ってやる！！」君はありったけの闘気を振り絞り、特攻した。","type":"battle","enemy_group_id":"215","choices":[{"label":"未来を繋ぐために、全てを捧げる","next":"text_post_battle"}],"battle_success_next":"text_post_battle"},"text_post_battle":{"text":"幾千もの閃光が交差したのち、大音響と共に最強の使徒が爆散した。だが君も限界だった。膝から崩れ落ち、霞む視界の中で天界の門が一時的に閉ざされていくのを見る。","type":"text","bg_key":"bg_spot_karyu_thunder","next":"text_post_battle2","choices":[{"label":"続ける","next":"text_post_battle2"}]},"text_post_battle2":{"text":"「……どうやら、俺の旅はここまでのようだ。だが……扉の在り処は、確かに示したぞ……」","type":"text","bg_key":"bg_spot_karyu_thunder","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"激戦の末、天界への門は吹き飛び、世界は一時的な静寂を取り戻した。君は「生ける伝説（英霊）」として歴史に名を残したが、神々への叛逆はまだ終わっていない。次なる世代へ、この剣と意志を継げ。（第3部完）","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6015;

-- 6016_main_ep16.csv (9 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"先代が神界の門を打ち破ってから、数十年の歳月が流れた。「生ける伝説」として名を残した初代は既にこの世になく、君はその遠い子孫、あるいは意志を継ぐ第二世代の傭兵だ。","type":"text","bg_key":"bg_tavern_night","bgm":"bgm_quest_calm","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"君は先代が遺した手記と、血塗られた古びた短剣を握りしめ、かつて彼らが集ったという伝説の酒場の扉を叩いた。","type":"text","bg_key":"bg_tavern_night","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"「よう、見ない顔だな。……いや、違うな。その眼の奥の狂気は、見覚えがある。手記を見るに、あいつの『跡継ぎ』ってわけか」","type":"text","bg_key":"bg_tavern_night","next":"text2_1","choices":[{"label":"続ける","next":"text2_1"}]},"text2_1":{"text":"薄暗い酒場の奥には、生気を失ってはいるが確かな存在感を放つ者たちが座っていた。彼らはかつて世界を救いかけた「英霊（シャドウ）」たちだ。","type":"text","bg_key":"bg_tavern_night","next":"text3","choices":[{"label":"続ける","next":"text3"}]},"text3":{"text":"彼らは初代が命と引き換えに刻んだ歴史の残滓であり、意志の強さを物語っている。君は手記をテーブルに叩きつけ、彼らをねめつけた。","type":"text","bg_key":"bg_tavern_night","next":"choice1","choices":[{"label":"「力を貸してくれ。終わらせに行く」","next":"text4"}]},"text4":{"text":"英霊の長がニヤリと笑う。「いいぜ。あいつが命と引き換えに繋いだこの道、無駄にはさせねぇ！行こうぜ、クソッタレな神々を殺しによ！」","type":"text","bg_key":"bg_tavern_night","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"だが平穏は長く続かない。酒場を出た直後、街の自警団に化けていた異形の刺客（堕天使）が襲い掛かる。継承の証を持つ者を消すためだ！","type":"battle","enemy_group_id":"216","choices":[{"label":"討破する","next":"text_post_battle"}],"battle_success_next":"text_post_battle"},"text_post_battle":{"text":"英霊たちの支援を受け、君はいとも簡単に刺客を退けた。先代の無念を晴らし、本当の世界の夜明けを取り戻すための、最後の旅がいま始まる。","type":"text","bg_key":"bg_road_night","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"「さて、まずは天に至るための『鍵』集めといこうか」英霊の声と共に、遠い空の向こうで雷鳴が轟いた。","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6016;

-- 6017_main_ep17.csv (10 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"次元の狭間を越え、神々の中枢たる「天界の玉座」へ至るには、4大国家が古代より秘匿管理してきた黄金の鍵が必要だ。","type":"text","bg_key":"bg_spot_roland_core","bgm":"bgm_quest_mystery","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"君は始まりの地、聖帝国ローランの王城に辿り着いた。かつて小隊長ガウェインが命を賭して守ろうとしたこの国の中心。","type":"text","bg_key":"bg_spot_roland_core","next":"text1_1","choices":[{"label":"続ける","next":"text1_1"}]},"text1_1":{"text":"だが、玉座の間へ続く「鉄の門」は固く閉ざされ、重装備の近衛兵団が槍を交差させて君の行く手を阻んでいる。","type":"text","bg_key":"bg_spot_roland_core","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"「ここから先は聖域である。帝の許可なき者の立ち入りは、いかなる理由があろうと死罪に処す」","type":"text","bg_key":"bg_spot_roland_core","next":"text2_1","choices":[{"label":"続ける","next":"text2_1"}]},"text2_1":{"text":"近衛隊長の眼には、狂信的な光が宿っていた。すでに各国の指導者層は、神々の精神支配を受けつつあるという噂は本当だったのだ。","type":"text","bg_key":"bg_spot_roland_core","next":"choice1","choices":[{"label":"「膨大な資産で通行証を提示する」","next":"text3"},{"label":"「強行突破する」","next":"battle"}]},"text3":{"text":"君はこれまでの世代が血の滲むような思いで積み上げた資産（20","next":"{\"type\":\"text\", \"bg\":\"bg_spot_roland_core\"}","choices":[{"label":"続ける","next":"{\"type\":\"text\", \"bg\":\"bg_spot_roland_core\"}"}]},"text3_1":{"text":"どれほど狂信に囚われていようとも、国家を動かすシステムとしての「富と権力」の重みは無視できない。門兵は青ざめ、黙って震える手で道を開けた。","type":"text","bg_key":"bg_spot_roland_core","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"battle":{"text":"問答無用で剣を抜く。「ならば力ずくでこじ開けるまでだ」。近衛隊長が激昂し、殺到する近衛兵団との激戦の火蓋が切られた！","type":"battle","enemy_group_id":"217","choices":[{"label":"神の操り人形たちを退ける","next":"text_win"}],"battle_success_next":"text_win"},"text_win":{"text":"血に染まる王城の階段。君は立ちはだかる精鋭たちを薙ぎ払い、強引に分厚い鉄の門をこじ開けた。「黄金の鍵」はすぐそこだ。","type":"text","bg_key":"bg_spot_roland_core","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"ついに神域へと至る鍵を手に入れた。しかしその直後、城全体を揺るがすほどの地響きが起こり、世界中で神々による「大粛清の儀式」が本格稼働を始めたという絶望的な報せが入る。","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6017;

-- 6018_main_ep18.csv (11 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"神々の大粛清の儀式が発動したことで、4大国家の指導者たちの理知は完全に神の呪縛に囚われた。彼らは互いを滅ぼし合う最終戦争「総力戦（四国会戦）」へと突入したのだ。","type":"text","bg_key":"bg_wasteland","bgm":"bgm_quest_crisis","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"荒野は四カ国の軍旗が入り乱れる、文字通りの地獄絵図と化していた。大地は血を吸い切れないほどに赤く染まり、空は硝煙と魔力で黒く濁っている。","type":"text","bg_key":"bg_wasteland","next":"text1_1","choices":[{"label":"続ける","next":"text1_1"}]},"text1_1":{"text":"兵士たちは皆、正気を失っている。自国の勝利すら目的ではなく、ただ「動くものを殺す」という残酷な命令だけを繰り返す、生きた屍に成り下がっていた。","type":"text","bg_key":"bg_wasteland","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"text":"ローランの大盾を連ねた重装歩兵団が、地響きを立てながら君に迫る！玉座へ向かうには、彼らの陣形を真っ向から破るしかない。","type":"battle","enemy_group_id":"218","choices":[{"label":"大盾ごと粉砕して突破する","next":"text2"}],"battle_success_next":"text2"},"text2":{"text":"ローランの陣地を抜けた直後、今度は夜の闇に紛れるように設計された夜刀の暗殺者集団が、白昼堂々側面から奇襲を掛けてきた！","type":"text","bg_key":"bg_wasteland","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"text":"「死ね、死ね、死ねぇ！」泡を吹きながら突っ込んでくる暗殺者たち。もはや過去の面影はない。","type":"battle","enemy_group_id":"219","choices":[{"label":"悲しみを切り捨てて迎え撃つ","next":"text3"}],"battle_success_next":"text3"},"text3":{"text":"息つく間もなく、天空からは華龍の飛龍船団が火球を雨のように降らせ、地上からはマルカンドの砂竜騎兵隊が砂塵を巻き上げて突進してくる！","type":"text","bg_key":"bg_wasteland","next":"battle3","choices":[{"label":"続ける","next":"battle3"}]},"battle3":{"text":"全方位からの同時攻撃。これは単なる人間同士の戦争ではない。世界そのものが君を排除しようと牙を剥いているのだ！","type":"battle","enemy_group_id":"219","choices":[{"label":"地獄の死線を越える","next":"text4"}],"battle_success_next":"text4"},"text4":{"text":"気が付けば、数キロにも及ぶ戦場を血まみれになりながら突破していた。鎧は砕け、剣は刃こぼれで鋸のようになっている。","type":"text","bg_key":"bg_wasteland","next":"text4_1","choices":[{"label":"続ける","next":"text4_1"}]},"text4_1":{"text":"君は無数の兵士たちの屍の山を築き、それを越えて、ついに「天界の玉座」へと続く神なる領域のふもとに足を踏み入れた。","type":"text","bg_key":"bg_wasteland","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"かつていがみ合った国家たちの無惨な末路。彼らに狂気を与え、歴史を遊戯として嘲笑ってきた天上の神々を、決して許すわけにはいかない。","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6018;

-- 6019_main_ep19.csv (9 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"神々が座す天界――「神域」への回廊は、冷たく透明なクリスタルで形成されていた。空間そのものが聖なる威圧感に満ちており、ただ息をするのすら苦しい。","type":"text","bg_key":"bg_boss_altar","bgm":"bgm_quest_crisis","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"足元には、数多の星々の瞬きや、下界で今なお続く戦争の炎が透けて見え、神々がどれほど高い場所から人間を見下してきたのかが痛いほど伝わってくる。","type":"text","bg_key":"bg_boss_altar","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"『神意ニ逆ラウ愚者ヨ。分ヲ弁エヌ傲慢ナル命ニ、天罰ヲ下ス』","type":"text","bg_key":"bg_boss_altar","next":"text2_1","choices":[{"label":"続ける","next":"text2_1"}]},"text2_1":{"text":"玉座へ続く天の回廊に、三対の黄金の翼を背負った、これまでの戦いでも見たことのない最高位の熾天使（神兵）が舞い降りた。神の門番だ。","type":"text","bg_key":"bg_boss_altar","next":"text3","choices":[{"label":"続ける","next":"text3"}]},"text3":{"text":"「……悪いが、こっちには死に急ぐ暇はないんでね。そこをどけ」君が剣を構えた、その時だった。","type":"text","bg_key":"bg_boss_altar","next":"text3_1","choices":[{"label":"続ける","next":"text3_1"}]},"text3_1":{"text":"君の背後にある裂け目から、荒々しい足音と共に何者かが次々と飛び込んでくる。彼らのマントには、ローラン、マルカンド、夜刀、華龍……様々な国の紋章が刻まれていた。","type":"text","bg_key":"bg_boss_altar","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"かつて国境で、砂漠で、街で共に戦った傭兵や兵士たちが、国境や人種の壁を越え、君という刃の『後陣』を務めるために駆けつけてきたのだ！","type":"battle","enemy_group_id":"220","choices":[{"label":"仲間と共に道を切り開く","next":"text_post_battle"}],"battle_success_next":"text_post_battle"},"text_post_battle":{"text":"「前だけ見て走れェ！背中の羽虫どもは俺たちが引き受ける！」傭兵たちの雄叫びを背に受け、君は最高位の神兵の胸を真っ向から貫き、弾き飛ばした。","type":"text","bg_key":"bg_boss_altar","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"無数の支援を受けながら、ついに最後の関門を突破した。全ての争いの元凶である主神の玉座へと続く、白亜の扉がゆっくりと開かれる。","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6019;

-- 6020_main_ep20.csv (13 nodes)
UPDATE scenarios SET script_data = '{"nodes":{"start":{"text":"次元の最果て、「天界の玉座」。目も眩むような光の中に浮かび上がるのは、人間の運命を盤上で弄んできた『主神』の姿だった。","type":"text","bg_key":"bg_boss_altar","bgm":"bgm_quest_crisis","next":"text1","choices":[{"label":"続ける","next":"text1"}]},"text1":{"text":"神には実体がなく、ただ純粋な光と魔力の濁流としてそこに座している。","type":"text","bg_key":"bg_boss_altar","next":"text1_1","choices":[{"label":"続ける","next":"text1_1"}]},"text1_1":{"text":"『理解不能。何故生キル。何故足掻ク。定メラレタ運命ノ中デ消エ行クコソガ、弱キ者ニ許サレタ唯一ノ救済ナリ。我ラガ定メタ均衡コソガ完璧ナリ』","type":"text","bg_key":"bg_boss_altar","next":"text2","choices":[{"label":"続ける","next":"text2"}]},"text2":{"text":"「黙れ……！俺たちが流した血は、お前たちの遊戯のためじゃない。俺たちが生きた意味は、俺たち自身で決める！」","type":"text","bg_key":"bg_boss_altar","next":"text2_1","choices":[{"label":"続ける","next":"text2_1"}]},"text2_1":{"text":"君は天に向かって力強く吠えた。その声に応えるかのように、先代たちから受け継いだ意志――「英霊」たちの残留魔力が、君の剣に黄金の光を帯びさせる。","type":"text","bg_key":"bg_boss_altar","next":"text3","choices":[{"label":"続ける","next":"text3"}]},"text3":{"text":"『愚カ者メ。神ノ威光ヲ前ニ、塵ト化セ』","type":"text","bg_key":"bg_boss_altar","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"text":"主神の怒りが具現化し、空間全体を覆い尽くすほどの巨大な『神竜』の姿を現した。泣いても笑っても、これが世界を賭けた最後の戦いだ！","type":"battle","enemy_group_id":"221","choices":[{"label":"主神へ決戦を挑む","next":"text4"}],"battle_success_next":"text4"},"text4":{"text":"神竜の放つ業火を掻き消し、君の光の剣が神の鱗を打ち砕く！","type":"text","bg_key":"bg_boss_altar","next":"text4_1","choices":[{"label":"続ける","next":"text4_1"}]},"text4_1":{"text":"『オォォォォォォォォォ！』絶叫と共に神竜が崩壊を始めるが、主神の核（コア）が暴走し、玉座もろとも君を道連れにしようと膨張し始めた。","type":"text","bg_key":"bg_boss_altar","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"text":"もはや小細工は通用しない。この一撃で暴走する核を貫けなければ、全てが終わる。全身の霊力を切っ先に集めろ！","type":"battle","enemy_group_id":"222","choices":[{"label":"未来を穿つ一撃を放つ","next":"text_post_battle"}],"battle_success_next":"text_post_battle"},"text_post_battle":{"text":"「うおおおおおおお！！」君の咆哮と共に放たれた一撃が、主神の核を正確に貫いた。数多の命を喰らい続けてきた神の力が、内部から連鎖的に崩壊していく。","type":"text","bg_key":"bg_boss_altar","next":"text_post_battle2","choices":[{"label":"続ける","next":"text_post_battle2"}]},"text_post_battle2":{"text":"君は吹き飛ばされ、意識が白く染まる直前……確かに、分厚い雲が晴れていくのを見た。","type":"text","bg_key":"bg_boss_altar","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"気がつけば君は、激戦を共に戦い抜いた仲間たちと地上に立っていた。遠い地平線に、見たこともないほど眩しい朝日――『蒼き暁』が昇り始めている。一人の傭兵から始まった長い長い旅路は、こうして誰も知らない本当の平和を掴み取ったのだ。","type":"end","result":"success","choices":[]}}}'::jsonb WHERE id = 6020;

